let probe;
try { probe = JSON.parse(($input.item.json.stdout || '{}').trim()); } catch { probe = { ok: false, reason: 'probe-parse-error' }; }
const url = ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/maintain/runbooks';
const ageDays = parseFloat(probe.backupAgeDays || '0');

if (probe.reason === 'no-backups-found') {
  return [{ json: {
    priority: 'P0',
    source: 'backup-restore-test',
    message: `No backups found in ${probe.backupDir}. Disaster recovery posture is broken — restore cannot succeed because there is nothing to restore.`,
    url
  } }];
}
if (!probe.ok) {
  return [{ json: {
    priority: 'P0',
    source: 'backup-restore-test',
    message: `Monthly restore probe FAILED · reason: ${probe.reason} · backup: ${probe.backup} (${ageDays}d old) · found PROGRESS.md: ${probe.foundProgress} · found ops/atlas.yaml: ${probe.foundAtlas}`,
    url
  } }];
}
// Restore passed. Flag stale backups (>40d) at P1, otherwise P2 confirmation.
if (ageDays > 40) {
  return [{ json: {
    priority: 'P1',
    source: 'backup-restore-test',
    message: `Restore probe PASSED but latest backup is ${ageDays}d old (>40d threshold). Backup cadence may have drifted. Backup: ${probe.backup}, ${probe.fileCount} files.`,
    url
  } }];
}
return [{ json: {
  priority: 'P2',
  source: 'backup-restore-test',
  message: `Monthly restore probe PASSED · backup: ${probe.backup} (${ageDays}d old) · ${probe.fileCount} files · sentinels present.`,
  url
} }];

const a = $('Assess restore').first().json;
// Strip ANSI noise + parse the original probe blob from the Telegram message-ish payload.
const priority = a.priority || 'P2';
const passed = priority !== 'P0';
const entry = {
  ts: new Date().toISOString(),
  priority,
  passed,
  // Pull what we can out of the message text — the source-of-truth probe object is the previous node's stdout.
  message: a.message || ''
};
return [{ json: entry }];
